#include <qpdf/BitWriter.hh>

// See comments in bits_functions.hh
#define BITS_WRITE 1
#include <qpdf/bits_functions.hh>

BitWriter::BitWriter(Pipeline* pl) :
    pl(pl)
{
}

void
BitWriter::writeBits(unsigned long long val, size_t bits)
{
    write_bits(this->ch, this->bit_offset, val, bits, this->pl);
}

void
BitWriter::writeBitsSigned(long long val, size_t bits)
{
    unsigned long long uval = 0;
    if (val < 0) {
        uval = (1ULL << bits) + static_cast<unsigned long long>(val);
    } else {
        uval = static_cast<unsigned long long>(val);
    }
    writeBits(uval, bits);
}

void
BitWriter::writeBitsInt(int val, size_t bits)
{
    writeBits(static_cast<unsigned long long>(val), bits);
}

void
BitWriter::flush()
{
    if (bit_offset < 7) {
        size_t bits_to_write = bit_offset + 1;
        write_bits(this->ch, this->bit_offset, 0, bits_to_write, this->pl);
    }
}

#include <qpdf/Pl_Count.hh>

#include <qpdf/QIntC.hh>
#include <qpdf/Util.hh>

using namespace qpdf;

class Pl_Count::Members
{
  public:
    Members() = default;
    Members(Members const&) = delete;
    ~Members() = default;

    // Must be qpdf_offset_t, not size_t, to handle writing more than size_t can handle.
    qpdf_offset_t count{0};
    unsigned char last_char{'\0'};
};

Pl_Count::Pl_Count(char const* identifier, Pipeline* next) :
    Pipeline(identifier, next),
    m(std::make_unique<Members>())
{
    util::assertion(next, "Attempt to create Pl_Count with nullptr as next");
}

Pl_Count::~Pl_Count() = default;
// Must be explicit and not inline -- see QPDF_DLL_CLASS in README-maintainer

void
Pl_Count::write(unsigned char const* buf, size_t len)
{
    if (len) {
        m->count += QIntC::to_offset(len);
        m->last_char = buf[len - 1];
        next()->write(buf, len);
    }
}

void
Pl_Count::finish()
{
    next()->finish();
}

qpdf_offset_t
Pl_Count::getCount() const
{
    return m->count;
}

unsigned char
Pl_Count::getLastChar() const
{
    return m->last_char;
}

